import { readFile, writeFile } from "node:fs/promises";

const projectUrl = new URL("../", import.meta.url);
const readSource = (path) => readFile(new URL(path, projectUrl), "utf8");

const [vocabularySource, coreSource, appSource, indexSource, stylesSource] = await Promise.all([
  readSource("src/vocabulary.js"),
  readSource("src/core.js"),
  readSource("src/app.js"),
  readSource("index.html"),
  readSource("styles.css")
]);

const vocabulary = vocabularySource.replace(/^export\s+/m, "");
const core = coreSource.replace(/^export\s+/gm, "");
const app = appSource.replace(
  /^import\s+{\s*VOCABULARY\s*}\s+from\s+["']\.\/vocabulary\.js["'];\r?\nimport\s+{[\s\S]*?}\s+from\s+["']\.\/core\.js["'];\r?\n/,
  ""
);
const banner = "// Generated by npm run build from the maintainable modules in src/.\n";
const bundle = `${banner}(() => {\n\"use strict\";\n${vocabulary}\n${core}\n${app}\n})();\n`;
const offlineHtml = indexSource
  .replace(
    '  <link rel="stylesheet" href="./styles.css">',
    `  <style>\n${stylesSource.replace(/<\/style/gi, "<\\/style")}\n  </style>`
  )
  .replace(
    '  <script src="./src/app.bundle.js"></script>',
    `  <script>\n${bundle.replace(/<\/script/gi, "<\\/script")}\n  </script>`
  );

await Promise.all([
  writeFile(new URL("src/app.bundle.js", projectUrl), bundle, "utf8"),
  writeFile(new URL("vocabulary-review-offline.html", projectUrl), offlineHtml, "utf8")
]);
